"""
Original Layer — 2 Chronicles chapters 18–20
Run: python3 scripts/zc-original-2chronicles-18-20.py

Ch18: Jehoshaphat allies with Ahab; Micaiah's true prophecy; Ramoth-gilead.
Ch19: Jehu's rebuke; Jehoshaphat's judicial reform throughout Judah.
Ch20: Moabite-Ammonite invasion; Jehoshaphat's great prayer; the Battle of Praise.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2_ORIGINAL_18_20 = {
  "18": {
    "1": "<p>Jehoshaphat had great riches and honor, and he made a marriage alliance with Ahab. The verb <em>wayyithattēn</em> (made a marriage alliance) is a reflexive formation from <em>ḥātān</em> (father-in-law/son-in-law) — the forging of covenant kinship through intermarriage. The Chronicler introduces this alliance immediately after Jehoshaphat&rsquo;s prosperity to signal the theological tension: wealth and honor do not protect against the seduction of dangerous alliances. The marriage of Jehoshaphat&rsquo;s son to Ahab&rsquo;s daughter (Athaliah, 2 Chr 21:6) will nearly destroy the Davidic line in the next generation.</p>",
    "2": "<p>After some years Jehoshaphat goes down to visit Ahab at Samaria — the direction word (<em>wayyērēḏ</em>, &ldquo;went down&rdquo;) signals a spiritual descent as much as a geographical one. Ahab slaughters sheep and cattle for Jehoshaphat in abundance, then <em>wayyᵉsîtēhû</em> (enticed/incited him) to go up against Ramoth-gilead. The verb <em>sût</em> (to incite/entice) is the same word used of Satan inciting David to the census (1 Chr 21:1) — the Chronicler signals that this alliance is spiritually dangerous.</p>",
    "3": "<p>Jehoshaphat says: <em>kāmônî ḵāmôḵā ûḵᵉʿammᵉḵā ʿammî wᵉʿimmᵉḵā bamilḥāmāh</em> — &ldquo;I am as you are, my people as your people. We will be with you in the war.&rdquo; This is the covenant solidarity formula — almost verbatim identical to Ruth&rsquo;s words to Naomi (Ruth 1:16 in reverse: &ldquo;your people shall be my people&rdquo;) — here applied to a military alliance with the apostate northern kingdom. The same formula that expresses loyal covenant love is here misapplied to a dangerous political marriage.</p>",
    "4": "<p>Jehoshaphat adds: <em>dᵉrāš-nāʾ kᵉyôm ʾet-dᵉḇar YHWH</em> — &ldquo;Inquire first for the word of YHWH.&rdquo; The characteristic Chronicler&rsquo;s verb <em>dāraš</em> (seek/inquire) is Jehoshaphat&rsquo;s instinct even in the midst of a compromised alliance. He insists on prophetic consultation before military action — the right instinct, though it will not prevent his error. The <em>kᵉyôm</em> (&ldquo;today/first&rdquo;) emphasizes the urgency: do not proceed without YHWH&rsquo;s word.</p>",
    "5": "<p>Ahab assembles 400 prophets who unanimously predict victory: &ldquo;Go up, for God will give it into the hand of the king.&rdquo; The suspicious unanimity of 400 prophets — all agreeing — already signals their inauthenticity. True prophets in the OT are rarely unanimous, especially when they are telling kings what kings want to hear. Jeremiah will later identify the false prophet precisely as the one who speaks &ldquo;peace, peace, when there is no peace&rdquo; (Jer 6:14; 8:11).</p>",
    "6": "<p>Jehoshaphat asks: <em>hăʾên pōh nāḇîʾ lYHWH ʿôḏ</em> — &ldquo;Is there not here another prophet of the LORD of whom we may inquire?&rdquo; The distinction between YHWH&rsquo;s prophet and Ahab&rsquo;s prophets is unstated but felt: Jehoshaphat senses the difference between prophets who serve the king and the prophet who speaks YHWH&rsquo;s word. The <em>ʿôḏ</em> (&ldquo;another/still&rdquo;) implies he already doubts the 400.</p>",
    "7": "<p>Ahab: <em>ʿôḏ ʾîš-ʾeḥāḏ liḏrōš ʾet-YHWH mēʾittô wᵉʾănî śᵉnēʾtîhû</em> — &ldquo;There is yet one man by whom we may inquire of YHWH, but I hate him, because he never prophesies good concerning me, but always evil.&rdquo; Ahab&rsquo;s self-indicting statement: he knows the difference between YHWH&rsquo;s true prophet (Micaiah) and his court prophets, but his criterion for rejecting Micaiah is personal — he speaks unwelcome truth. The prophetic office of truth-telling that costs its bearer persecution reaches its apex in Jesus (John 8:40; Matt 23:29-31).</p>",
    "8": "<p>Ahab calls Micaiah ben Imlah. Micaiah is named and his father named — he is a real, locatable person, not a generic prophet. The Chronicler preserves historical specificity even in a narrative borrowed from Kings. The king&rsquo;s officer who is sent for Micaiah is told to bring him — Micaiah is apparently under some constraint, perhaps under a previous prophetic arrest (1 Kgs 22:26-27 gives the background).</p>",
    "9": "<p>The two kings sit on their thrones, arrayed in their robes, at the threshing floor at the entrance to the gate of Samaria. The threshing floor (<em>gōren</em>) as an official meeting place recalls the threshing floor of Ornan where David&rsquo;s altar was built (1 Chr 21:18) and where Solomon&rsquo;s temple would stand — a location with atonement overtones. The 400 prophets prophesying before the kings is a spectacle of royal religion in all its compromised splendor.</p>",
    "10": "<p>Zedekiah son of Chenaanah makes himself iron horns and declares: <em>kōh-ʾāmar YHWH bᵉʾēlleh tᵉnaggaḥ ʾet-ʾĂrām</em> — &ldquo;Thus says the LORD: With these you shall push the Syrians until they are destroyed.&rdquo; The symbolic action of iron horns is a prophetic theater-act, but it invokes the LORD&rsquo;s authority without having received the LORD&rsquo;s word. The false prophet&rsquo;s greatest danger is not outright fabrication but the confident use of divine language for self-serving predictions.</p>",
    "11": "<p>All 400 prophets prophesy the same: <em>ʿălēh Rāmōt Gilʿāḏ wᵉhaṣlîaḥ</em> — &ldquo;Go up to Ramoth-gilead and succeed.&rdquo; The verbal root <em>ṣlḥ</em> (to succeed/prosper) is the Chronicler&rsquo;s key word for the outcome of covenant faithfulness. That 400 prophets use it here for a venture that will end in disaster is the Chronicler&rsquo;s irony: <em>ṣlḥ</em> without YHWH&rsquo;s actual word is empty.</p>",
    "12": "<p>The officer tells Micaiah: the 400 prophets speak with one voice — &ldquo;let your word be like one of theirs&rdquo; — a blatant invitation to conform. <em>Ûḏabbēr ṭôḇ</em> (&ldquo;speak good&rdquo;) is the pressure that every true prophet faces: accommodate the consensus. Micaiah&rsquo;s response (v13) sets up the great contrast between prophetic conformity and prophetic faithfulness.</p>",
    "13": "<p><em>Ḥay-YHWH kî ʾēt ʾăšer-yōʾmar ʾĕlōhay ʾōtô ʾᵃḏabbēr</em> — &ldquo;As YHWH lives, whatever my God says, that I will speak.&rdquo; The oath formula <em>ḥay-YHWH</em> invokes the living God as witness to the prophet&rsquo;s integrity. The switch from &ldquo;YHWH&rdquo; to <em>ʾĕlōhay</em> (&ldquo;my God&rdquo;) in the middle of the verse is significant: Micaiah speaks in terms of personal relationship — this is his God, not merely the God of the institution.</p>",
    "14": "<p>Micaiah arrives and immediately mirrors the 400: <em>ʿălû wᵉhaṣlîḥû wᵉyinnāṯᵉnû bᵉyaḏᵉḵem</em> — &ldquo;Go up and succeed; they will be given into your hand.&rdquo; This is deliberate irony — Micaiah uses the exact words of the false prophets, and Ahab immediately recognizes it as mockery (v15). The true prophet deliberately adopts the form of false prophecy to expose its emptiness, forcing Ahab to request the actual truth.</p>",
    "15": "<p>Ahab adjures Micaiah: <em>kammeh pᵉʿāmîm ʾănî mašbîʿᵉḵā ʾăšer lōʾ tᵉḏabbēr ʾēlay raq-ʾemet</em> — &ldquo;How many times shall I make you swear that you speak to me nothing but the truth in the name of the LORD?&rdquo; Ahab knows Micaiah is mocking him. The king who has rejected YHWH&rsquo;s word still recognizes it when he hears its absence. The conscience that recognizes truth even when the will refuses it is one of Scripture&rsquo;s most poignant ironies.</p>",
    "16": "<p>Micaiah&rsquo;s true vision: <em>rāʾîtî ʾet-kol-Yiśrāʾēl nᵉpûṣîm ʿal-hehārîm kᵉṣōʾn ʾăšer ʾên-lāhem rōʿeh</em> — &ldquo;I saw all Israel scattered on the mountains as sheep that have no shepherd.&rdquo; The image of leaderless sheep (<em>ṣōʾn ʾăšer ʾên-lāhem rōʿeh</em>) is the OT&rsquo;s most frequent pastoral image for a people in crisis (Num 27:17; Ezek 34:5). It is the direct background for Jesus&rsquo; compassion on the crowds who were &ldquo;like sheep without a shepherd&rdquo; (Matt 9:36; Mark 6:34).</p>",
    "17": "<p>Ahab says to Jehoshaphat: &ldquo;Did I not tell you that he would not prophesy good concerning me, but evil?&rdquo; — <em>hālōʾ ʾāmartî ʾēleḵā lōʾ yitnabbēʾ ʿālay ṭôḇ kî ʾim-rāʿ</em>. Ahab demonstrates the perverse self-knowledge of the willfully disobedient: he knows the true prophet speaks unwelcome truth, he has asked for the truth, and now that he has heard it he retreats to resentment. The knowledge that does not lead to obedience only deepens condemnation (John 9:41; Rom 1:21).</p>",
    "18": "<p>Micaiah continues: &ldquo;Therefore hear the word of the LORD: I saw the LORD sitting on his throne, and all the host of heaven standing on his right and on his left.&rdquo; The heavenly throne-room vision grants the prophet a view behind the visible world — the <em>ṣᵉḇāʾ haššāmayim</em> (host of heaven) arrayed before YHWH parallels Isaiah&rsquo;s throne-room vision (Isa 6:1-3) and the divine council imagery of Job 1-2. The prophet who has access to this scene speaks with a different authority than those who only mirror the king&rsquo;s wishes.</p>",
    "19": "<p>YHWH asks: <em>mî yᵉfatteh ʾet-ʾAḥāḇ</em> — &ldquo;Who will entice Ahab that he may go up and fall at Ramoth-gilead?&rdquo; The divine permission of deception — YHWH soliciting the means of Ahab&rsquo;s ruin — is theologically significant. The <em>pittāh</em> (to entice/seduce) is the same verb used of Eve&rsquo;s temptation (Gen 3:13), Potiphar&rsquo;s wife (Gen 39:7), and Samson&rsquo;s seduction. God does not cause the deception but permits and employs the spiritual reality that judgment on the persistently wicked sometimes involves confirmation of their chosen blindness (Isa 6:10; Rom 1:24-28).</p>",
    "20": "<p>Various members of the heavenly council propose options; then a <em>rûaḥ</em> (spirit) comes forward: <em>wayyēṣēʾ hārûaḥ wayyaʿămoḏ lipnê YHWH</em> — &ldquo;Then a spirit came forward and stood before the LORD.&rdquo; The personified spirit before the divine council echoes the <em>śāṭān</em> figure in Job 1:6 and Zech 3:1-2 — a spiritual being operating within the divine court with a specific function. The heavenly council scene asserts divine sovereignty: nothing happens outside YHWH&rsquo;s knowledge and permission, even the deception of apostate kings.</p>",
    "21": "<p>The spirit says: <em>ʾēṣēʾ wᵉhāyîtî rûaḥ šeqer bᵉpî kol-nᵉḇîʾāyw</em> — &ldquo;I will go out and be a lying spirit in the mouth of all his prophets.&rdquo; <em>Rûaḥ šeqer</em> (lying/false spirit) — YHWH says, &ldquo;You are to entice him, and you shall succeed.&rdquo; The divine permission here is not divine authorship of the lie: the false prophets&rsquo; willingness to deceive is already established; YHWH permits the spirit to exploit that established disposition. The theological principle: God&rsquo;s hardening judgments confirm and deepen what the human will has already chosen (Exod 4:21; Rom 9:18).</p>",
    "22": "<p><em>YHWH nātan rûaḥ šeqer bᵉpî nᵉḇîʾêḵā ʾēlleh wYHWH dibbēr ʿāleḵā rāʿāh</em> — &ldquo;The LORD has put a lying spirit in the mouth of these your prophets. The LORD has declared disaster for you.&rdquo; Micaiah&rsquo;s conclusion integrates divine sovereignty and human responsibility: the false prophets are genuinely lying (their guilt is real), yet YHWH&rsquo;s purposes encompass their lie. The NT holds the same tension: Judas betrayed Christ by his own will, yet it happened &ldquo;according to the definite plan and foreknowledge of God&rdquo; (Acts 2:23).</p>",
    "23": "<p>Zedekiah son of Chenaanah strikes Micaiah on the cheek and demands: <em>ʾê-zeh dereḵ ʿāḇar rûaḥ-YHWH mēʾittî lᵉḏabbēr ʾōtāḵ</em> — &ldquo;Which way did the Spirit of YHWH go from me to speak to you?&rdquo; The physical violence against the true prophet who contradicts the court prophets anticipates the persecution of Jesus (Matt 26:67-68; John 18:22-23): the blow to the face is the false prophet&rsquo;s response to prophetic exposure. Micaiah&rsquo;s reply — &ldquo;You will see on that day when you go from chamber to chamber to hide yourself&rdquo; — sets the self-validating test of the true prophecy.</p>",
    "24": "<p><em>wayyōʾmer Mîḵāyᵉhû hinnᵉḵā rōʾeh bayyôm hahûʾ ʾăšer tābōʾ ḥeder bᵉḥeḏer lᵉhēḥābēʾ</em> — &ldquo;Behold, you shall see on that day when you go from chamber to chamber to hide yourself.&rdquo; The self-fulfillment criterion of true prophecy (Deut 18:21-22): Micaiah offers the proof of his authority — when the battle ends in disaster, Zedekiah will be the one hiding. The contrast with the false prophet is not just content but consequence: false prophecy creates no accountability; true prophecy stakes its authority on historical outcomes.</p>",
    "25": "<p>Ahab orders Micaiah put in prison and fed minimum rations: <em>lāḥem laḥaṣ ûmayim laḥaṣ ʿaḏ-šûḇî bᵉšālôm</em> — &ldquo;bread of affliction and water of affliction, until I return in peace.&rdquo; The imprisonment of the prophet echoes Jeremiah (Jer 37:15), John the Baptist (Matt 14:3), and ultimately Christ (John 18:12). The pattern of power imprisoning truth recurs because every institutional authority that has committed to a course of action finds the prophetic voice inconvenient.</p>",
    "26": "<p>Micaiah&rsquo;s final word: <em>ʾim-šôḇ tāšûḇ bᵉšālôm lōʾ-dibbēr YHWH bî</em> — &ldquo;If you return in peace, the LORD has not spoken by me.&rdquo; This is the prophet&rsquo;s signature: I stake my prophetic authority on this word. If Ahab returns safely, I am a false prophet. The courage of this declaration — made to a king who has just ordered imprisonment — is the hallmark of the true prophetic vocation: not self-preservation but YHWH&rsquo;s honor.</p>",
    "27": "<p><em>wayyōʾmer šimʿû ʿammîm kullām</em> — &ldquo;And he said, &lsquo;Hear, all you peoples!&rsquo;&rdquo; Micaiah&rsquo;s public declaration that the assembled nations will witness the outcome broadens the scope of the prophetic test from king and court to all peoples. The true prophetic word is not private — it is addressed to the widest possible audience as a public claim about YHWH&rsquo;s governance of history.</p>",
    "28": "<p>The kings of Israel and Judah go up to Ramoth-gilead. The battle proceeds despite Micaiah&rsquo;s warning — the momentum of human ambition and the pressure of 400 court prophets overwhelm one voice of truth. The narrative logic of prophetic rejection reaching its inevitable conclusion is the Chronicler&rsquo;s demonstration that rejection of YHWH&rsquo;s word does not change its content; it only changes the hearer&rsquo;s relationship to its outcome.</p>",
    "29": "<p>Ahab says to Jehoshaphat: <em>hitḥappēś wābōʾ bammiḥlāmāh wᵉʾattāh lᵉḇôš bᵉḡāḏêḵā</em> — &ldquo;I will disguise myself and go into battle, but you wear your robes.&rdquo; Ahab&rsquo;s strategy to evade Micaiah&rsquo;s prophecy by disguise is the attempt to outmaneuver divine foreknowledge — as if YHWH&rsquo;s word is about Ahab-in-his-robes rather than about Ahab himself. The irony is complete: Ahab&rsquo;s disguise does not save him; a random arrow finds him anyway (v33). Providence cannot be evaded by costume.</p>",
    "30": "<p>The king of Syria commands: attack no one small or great, only the king of Israel. The strategic targeting of the king — his single person amid the whole army — is the human equivalent of YHWH&rsquo;s specific judgment on Ahab. The Syrian army obeys orders by targeting the king; the random arrow disobeys orders by hitting a disguised man who happens to be the king. Both converge on the same divinely ordained outcome.</p>",
    "31": "<p>The Syrian chariot commanders pursue Jehoshaphat thinking he is the king of Israel — Jehoshaphat cries out (<em>wayyizʿaq</em>), and YHWH helps him (<em>waYHWH ʿăzārô wᵉsîtēm ʾĕlōhîm mēʾālāyw</em>). The same verb <em>sût</em> (entice/turn away) used of Ahab&rsquo;s enticement to battle (v2) is used here of God turning the Syrians from Jehoshaphat — a verbal echo: Jehoshaphat was enticed by Ahab; God removes the Syrian entrapment from Jehoshaphat. The cry to YHWH in extremity is the one act that distinguishes Jehoshaphat from Ahab.</p>",
    "32": "<p>The Syrian commanders see that Jehoshaphat is not the king of Israel and turn back from pursuing him. The divine rescue follows the cry for help — prayer at the moment of extremity produces divine intervention. The Chronicler presents this as a direct causal connection: <em>wayyizʿaq</em> (he cried out) → <em>waYHWH ʿăzārô</em> (YHWH helped him). The cry of distress to YHWH is never wasted (Ps 34:17; 50:15; 107:6).</p>",
    "33": "<p><em>wᵉʾîš māšaḵ baqqešet lᵉtummô wayyakkeh ʾet-melek Yiśrāʾēl</em> — &ldquo;But a certain man drew his bow at random and struck the king of Israel.&rdquo; <em>Lᵉtummô</em> means &ldquo;in his simplicity/at random&rdquo; — without intention, without aim, without knowledge of his target. The &ldquo;random&rdquo; arrow that finds the one man in disguise among thousands is the Chronicler&rsquo;s most precise statement of providential specificity: what humans call chance is YHWH&rsquo;s precision. There are no random events in the narrative of divine judgment (Prov 16:33).</p>",
    "34": "<p>Ahab is propped up in his chariot facing the Syrians until evening — <em>wayyimot bāʿereḇ</em> — and he dies at sunset. The image of the mortally wounded king sustained in his chariot, still facing the battle, until sunset — when the fighting ends (Deut 24:15 establishes sunset as the end of the day&rsquo;s work) — is one of the most powerful death scenes in Chronicles. Ahab&rsquo;s death fulfills Micaiah&rsquo;s word precisely (v16): Israel scattered, the king dead.</p>"
  },
  "19": {
    "1": "<p>Jehoshaphat returns to his house in Jerusalem in peace (<em>bᵉšālôm</em>) — the very condition Ahab claimed would prove Micaiah a false prophet (18:26). Jehoshaphat&rsquo;s safe return is YHWH&rsquo;s mercy on the compromised king who cried out in extremity. The peace he returns to is not the peace of the righteous but the grace granted to the repentant — and it comes with a prophetic rebuke (v2).</p>",
    "2": "<p>Jehu son of Hanani rebukes Jehoshaphat: <em>hᵃlārāšāʿ laʿăzōr ûmᵉśōnᵉʾê YHWH tᵉʾāhāḇ</em> — &ldquo;Should you help the wicked and love those who hate the LORD?&rdquo; The two verbs — <em>ʿāzar</em> (help) and <em>ʾāhēḇ</em> (love) — name the covenant bonds that Jehoshaphat has misapplied: the <em>ḥesed</em> (loyal love) that belongs to fellow covenant-keepers has been extended to the LORD&rsquo;s enemies. Prophetic rebuke after narrow escape is the Chronicler&rsquo;s pedagogical pattern: grace is followed by instruction on why grace was needed.</p>",
    "3": "<p><em>ʾăḇāl dᵉḇārîm ṭôḇîm nimṣᵉʾû ḇāḵ</em> — &ldquo;Nevertheless, some good is found in you.&rdquo; The word <em>ʾăḇāl</em> (&ldquo;but/nevertheless/however&rdquo;) is the pivot of the rebuke: the prophet acknowledges genuine goods before cataloguing failures. Jehoshaphat has destroyed the Asherahs (<em>haʾăšērôt</em>) and set his heart to seek God (<em>lāḏᵉrōš ʾĕlōhîm</em>). The Chronicler&rsquo;s balanced accounting — good noted alongside failure — models the nuanced evaluation of human character that neither whitewashes nor despairs.</p>",
    "4": "<p>Jehoshaphat goes out among the people from Beersheba to the hill country of Ephraim and brings them back to YHWH. The king as itinerant reformer — personally traversing the land to restore covenant faithfulness — is a distinctly Chronicler theme. The geographic sweep from <em>Bᵉʾēr-šeḇaʿ ʿaḏ-har ʾeprayim</em> signals the pan-Israelite reach of the reform: from the deep south to what was once the northern heartland.</p>",
    "5": "<p>Jehoshaphat appoints judges (<em>šōpᵉṭîm</em>) in all the fortified cities of Judah, city by city. The judicial reform — establishing an infrastructure of legal accountability throughout the kingdom — is the institutional expression of the theological principle: YHWH&rsquo;s justice must be embodied in human structures. The legal-reform initiative echoes Moses&rsquo; establishment of judges (Exod 18:13-27; Deut 16:18-20) and anticipates the NT vision of the church as a community of justice.</p>",
    "6": "<p>Jehoshaphat charges the judges: <em>rᵉʾû mah-ʾatttem ʿōśîm kî lōʾ lāʾādām tišpᵉṭû kî lYHWH</em> — &ldquo;Consider what you do, for you judge not for man but for the LORD.&rdquo; The theological grounding of human justice is radical: judges do not merely serve social order; they execute YHWH&rsquo;s own judgment on his behalf. <em>Lōʾ lāʾādām... kî lYHWH</em> (not for man but for the LORD) establishes divine accountability as the ground of judicial integrity. He will be with them in the matter of judgment.</p>",
    "7": "<p><em>wᵉʿattāh yᵉhî paḥaḏ-YHWH ʿălêḵem šimrû waʿăśû kî-ʾên ʿim-YHWH ʾĕlōhênû ʿawlāh ûmᵉśōʾ pānîm wᵉmiqqaḥ-šōḥaḏ</em> — &ldquo;The fear of the LORD be upon you. Take care what you do, for there is no injustice (<em>ʿawlāh</em>) with the LORD our God, no partiality (<em>mᵉśōʾ pānîm</em> — literally &lsquo;lifting of faces&rsquo;), no taking of bribes (<em>miqqaḥ-šōḥaḏ</em>).&rdquo; Three negatives define divine character: no iniquity, no face-lifting (= favoritism, preferring the powerful), no bribery. The human judge is to mirror the divine judge in all three dimensions.</p>",
    "8": "<p>In Jerusalem Jehoshaphat appoints some Levites and priests and heads of families as a high court. The two-tier judicial system — local judges in the cities (vv5-7) and a high court in Jerusalem (vv8-11) — mirrors the Mosaic structure of Exod 18 (local judges + Moses as appeals court). The judicial infrastructure is not merely administrative but theological: the Jerusalem court handles cases that are &ldquo;the LORD&rsquo;s concerns&rdquo; as well as those of the king.</p>",
    "9": "<p>Jehoshaphat charges the high court: <em>kōh taʿăśûn bᵉyirʾat YHWH beʾemet ûḇᵉlēḇāḇ šālēm</em> — &ldquo;Thus you shall do in the fear of the LORD, in faithfulness (<em>beʾemet</em>), and with a whole heart (<em>bᵉlēḇāḇ šālēm</em>).&rdquo; The three-part charge combines the dispositional (<em>yirʾat YHWH</em>), the epistemic (<em>beʾemet</em>), and the relational (<em>lēḇāḇ šālēm</em>) — the Chronicler&rsquo;s signature phrase appearing here in the judicial context. Judicial integrity is an expression of whole-hearted covenant devotion.</p>",
    "10": "<p>The high court is to handle any case: bloodshed or law, commandment, statute, or rule — instructing people so they may not become guilty before YHWH. <em>Wᵉhizkarttem ʿălêhem wᵉlōʾ yiʾšᵉmû lYHWH</em> — &ldquo;Thus you shall warn them, so that wrath may not come upon you and your brothers.&rdquo; The judicial function includes a teaching dimension (<em>hizzîr</em> = to warn/instruct) — the court is an instrument of covenant education as much as legal adjudication.</p>",
    "11": "<p>Amariah the chief priest presides over all matters of the LORD, and Zebadiah the ruler of Judah presides over the king&rsquo;s matters. The dual leadership — priestly and civil — reflects the Chronicler&rsquo;s consistent theocratic vision where the two orders (priest and king) operate in distinct but complementary spheres. <em>Ḥizqû waʿăśû</em> — &ldquo;Take courage and do it.&rdquo; The Levites are officers to aid them in this work.</p>"
  },
  "20": {
    "1": "<p>After this the Moabites and Ammonites, with some of the Meunites, come against Jehoshaphat for battle. The coalition of three peoples — Moab, Ammon, Meunites — who shared ancestry with Israel (Moab and Ammon descended from Lot) attacks the covenanting nation from within its own region. The threat comes precisely when Jehoshaphat&rsquo;s reform is underway — the Chronicler&rsquo;s pattern: faithfulness generates spiritual opposition (cf. Nehemiah rebuilding the wall while enemies mock and threaten).</p>",
    "2": "<p>Messengers report: &ldquo;A great multitude is coming against you from Edom, from beyond the sea.&rdquo; The <em>hāmôn rāḇ</em> (great multitude) — the Chronicler&rsquo;s favored phrase for overwhelming numerical odds — sets up the theological contrast: the size of the enemy force is precisely what makes YHWH&rsquo;s deliverance all the more manifest. Every great military challenge in Chronicles creates the opportunity for YHWH to demonstrate that the battle belongs to him, not to human military capacity.</p>",
    "3": "<p><em>wayyîrāʾ wayyittēn Yᵉhôšāpāṭ pānāyw liḏrôš laYHWH</em> — &ldquo;Then Jehoshaphat was afraid and set his face to seek the LORD.&rdquo; The sequence — fear followed by seeking YHWH — is the Chronicler&rsquo;s model of proper crisis response. Fear is not itself failure (it registers the reality of the threat); failure would be responding to fear with human strategy alone. <em>Wayyikroz ṣôm ʿal-kol-Yᵉhûḏāh</em> — he proclaims a fast on all Judah: a communal act of dependence on YHWH.</p>",
    "4": "<p>Judah assembles to seek help from the LORD (<em>liḇaqqēš mēYHWH</em>); from all the cities of Judah they come to seek the LORD. The corporate seeking — the whole nation gathering to pray — is the Chronicler&rsquo;s ideal of communal covenant response to crisis. The vocabulary of seeking (<em>dāraš, bāqaš</em>) saturates the passage (vv3, 4, 7), establishing the theological motif: the battle&rsquo;s outcome depends on whether YHWH is sought.</p>",
    "5": "<p>Jehoshaphat stands in the assembly of Judah and Jerusalem in the house of the LORD before the new court. The king praying in the temple before the gathered nation is the Solomonic model (2 Chr 6) enacted by his descendant in crisis. The public, communal nature of the prayer — standing before YHWH in the temple precinct — emphasizes that this is not private petition but covenantal intercession on behalf of the whole people.</p>",
    "6": "<p><em>YHWH ʾĕlōhê ʾăḇōtênû hălōʾ ʾattāh-hûʾ ʾĕlōhîm baššāmayim ûmōšēl bᵉḵōl mamlᵉḵôt haggôyim ûḇᵉyāḏᵉḵā kōaḥ ûgᵉḇûrāh wᵉʾên ʿimmᵉḵā lᵉhityaṣṣēḇ</em> — &ldquo;O LORD, God of our fathers, are you not God in heaven? You rule over all the kingdoms of the nations. In your hand are power and might, so that none is able to withstand you.&rdquo; The prayer opens with a declaration of divine sovereignty: heaven-ruler, nation-ruler, invincible power. The logic of petition follows from this declaration: if YHWH rules all nations, then even this attacking coalition is within his authority to restrain or redirect.</p>",
    "7": "<p><em>hălōʾ ʾattāh ʾĕlōhênû hôraštā ʾet-yōšᵉḇê hāʾāreṣ hazzōʾt millipnê ʿammᵉḵā Yiśrāʾēl wattittᵉnāh lᵉzaraʿ ʾAḇrāhām ʾōhăḇᵉḵā lᵉʿôlām</em> — &ldquo;Did you not, our God, drive out the inhabitants of this land before your people Israel, and give it forever to the descendants of Abraham your friend?&rdquo; <em>ʾōhăḇᵉḵā</em> (your friend/your lover) — Abraham called the friend of God (Isa 41:8; Jas 2:23). The land&rsquo;s gift to the seed of the friend of God is the basis of the appeal: what YHWH gave through prior covenant action, let him now defend.</p>",
    "8": "<p>The descendants of Abraham have lived in the land and built a sanctuary for YHWH&rsquo;s name — a place to cry out in distress and be heard. The reference to Solomon&rsquo;s temple-dedication prayer (2 Chr 6:28-31) is explicit: the temple was built precisely for this moment — when enemies, sword, plague, or famine drive Israel to prayer, YHWH promised to hear from this place. Jehoshaphat is doing exactly what Solomon prayed for: <em>wᵉqārāʾnû ʾēleḵā</em> — we cry to you.</p>",
    "9": "<p><em>bārāʿāh ḥereḇ šᵉpôṭ wāḏeḇer ûrāʿāḇ naʿămōḏ lipnê habbayit hazzeh wᵉlᵉpāneḵā</em> — &ldquo;If disaster comes upon us, the sword, judgment, or pestilence, or famine, we will stand before this house and before you.&rdquo; The fourfold covenant-curse list (war, sword, plague, famine) comes directly from Deut 28 and Lev 26 — the very curses that covenant unfaithfulness brings. Jehoshaphat invokes them to demonstrate that he knows the structure of the covenant and is claiming the temple&rsquo;s intercessory role within it.</p>",
    "10": "<p>Jehoshaphat notes the theological irony: Israel was commanded not to attack Moab, Ammon, and Mount Seir when coming out of Egypt (Deut 2:4-9) — they turned away from them. Now these peoples attack Israel in return for that forbearance. The prayer invokes Israel&rsquo;s past obedience to YHWH&rsquo;s command as a basis for present protection: we were merciful at your command; do not let the recipients of that mercy become our destroyers.</p>",
    "11": "<p><em>hinnām gōmᵉlîm ʿālênû lābōʾ lᵉgārᵉšênû miyyᵉrušātᵉḵā ʾăšer hôraštā lānû</em> — &ldquo;Behold, they reward us by coming to drive us out of your possession that you have given us to inherit.&rdquo; The land is identified as <em>yᵉrušātᵉḵā</em> (your possession) — not Israel&rsquo;s ownership but YHWH&rsquo;s inheritance entrusted to his people. The attack on Israel is therefore an attack on YHWH&rsquo;s estate. The prayer frames human crisis within divine ownership: to defend Israel is to defend YHWH&rsquo;s own territory.</p>",
    "12": "<p><em>ʾĕlōhênû hălōʾ tišpāṭ-bām kî ʾên bānû kōaḥ lipnê hehāmôn hārāḇ hazzeh habbāʾ ʿālênû wᵉʾănaḥnû lōʾ nēḏaʿ mah-naʿăśeh kî ʿāleḵā ʿênênû</em> — &ldquo;O our God, will you not execute judgment on them? For we are powerless against this great horde that is coming against us. We do not know what to do, but our eyes are on you.&rdquo; The climactic confession of total dependence — <em>lōʾ nēḏaʿ mah-naʿăśeh</em> (we do not know what to do) followed by <em>ʾêneynû ʿāleḵā</em> (our eyes are on you) — is one of the most complete prayer-postures in Scripture. The acknowledgment of ignorance and the directional focus on YHWH replaces self-reliance with covenant trust.</p>",
    "13": "<p>All Judah stands before YHWH — their little ones, wives, and children. The corporate posture of the whole community — including those who cannot fight (the little ones, wives) — is the human complement to the prayer of vv6-12. The entire covenant community, not just its warriors, stands in the divine presence as suppliants. This whole-community stance before YHWH prefigures the gathering of all believers before the throne (Rev 7:9-10).</p>",
    "14": "<p>The Spirit of YHWH (<em>rûaḥ YHWH</em>) comes upon Jahaziel son of Zechariah — a Levite of the sons of Asaph — in the midst of the assembly. The prophetic Spirit falls on a Levitical singer, not a priestly or royal figure — affirming that the Spirit distributes gifts as he wills (1 Cor 12:11). The divine response to corporate prayer comes through a member of the worshiping community, not through the king or priest alone.</p>",
    "15": "<p><em>hiqšîḇû kol-Yᵉhûḏāh wᵉyōšᵉḇê Yᵉrûšālaim wᵉhammeleḵ Yᵉhôšāpāṭ kōh-ʾāmar YHWH lāḵem ʾattam lōʾ tîrᵉʾû wᵉlōʾ tēḥattû... kî lōʾ lāḵem hammiqlāmāh kî lēʾlōhîm</em> — &ldquo;Thus says the LORD to you: &lsquo;Do not be afraid and do not be dismayed at this great horde, for the battle is not yours but God&rsquo;s.&rsquo;&rdquo; <em>Lōʾ lāḵem hammiqlāmāh kî lēʾlōhîm</em> — the battle is not yours but God&rsquo;s. The divine warrior theology of holy war: Israel does not fight this battle; YHWH does. The human role is obedience and witness, not military force.</p>",
    "16": "<p>The oracle directs: go down against them tomorrow; they come up by the ascent of Ziz (<em>maʿălēh haṣîṣ</em>), and they will be found at the end of the valley before the wilderness of Jeruel. The specific tactical intelligence — precise location, precise time — is the sign that this is a genuine divine oracle. False prophets speak in vague terms that can be claimed after any outcome; true oracles provide verifiable specifics.</p>",
    "17": "<p><em>lōʾ lāḵem lehillāḥēm baqqerāḇ hazzeh hiṣṣîḇû ʿimᵉḏû ûrᵉʾû ʾet-yᵉšûʿat YHWH ʾittᵉḵem Yᵉhûḏāh wîrûšālaim</em> — &ldquo;You will not need to fight in this battle. Stand firm, hold your position, and see the salvation of the LORD on your behalf.&rdquo; <em>Rᵉʾû ʾet-yᵉšûʿat YHWH</em> — &ldquo;see the salvation of YHWH&rdquo; — the same root as Yeshua/Joshua: see the <em>yᵉšûʿāh</em> of YHWH. The command is not to fight but to position and watch: Moses at the Red Sea (Exod 14:13: <em>rᵉʾû ʾet-yᵉšûʿat YHWH</em> — identical phrase) is the explicit template.</p>",
    "18": "<p>Jehoshaphat bows with his face to the ground, and all Judah and the inhabitants of Jerusalem fall before YHWH in worship (<em>wayyištaḥăwû lYHWH</em>). Worship precedes battle — before a single soldier moves, the entire nation prostrates itself. The Levites of the sons of Kohath and sons of Korah stand up to praise YHWH with a very loud voice. The battle strategy begins with corporate worship, not tactical briefing.</p>",
    "19": "<p>The Levitical singers rise to praise YHWH with a loud voice (<em>bᵉqôl gāḏôl lᵉmaʿlāh</em> — &ldquo;in an exceedingly loud voice&rdquo;). The volume of the praise matches the size of the threat: the louder the danger, the louder the worship. The Chronicler&rsquo;s vision of Levitical praise as a military instrument culminates in this scene — the singers who are exempted from other duties for continuous praise (1 Chr 9:33) now lead the army to battle.</p>",
    "20": "<p><em>wayyašḵîmû babbōqer wayyēṣᵉʾû lᵉmiḏbar Tᵉqôaʿ</em> — they rise early in the morning and go out to the wilderness of Tekoa. Jehoshaphat addresses the army: <em>haʾămînû bYHWH ʾĕlōhêḵem wᵉtêʾāmēnû haʾămînû bᵉnᵉḇîʾāyw wᵉhaṣlîḥû</em> — &ldquo;Believe in the LORD your God, and you will be established (<em>tēʾāmēnû</em>); believe his prophets, and you will succeed.&rdquo; The wordplay on <em>ʾāman</em> (believe/be established/Amen) is untranslatable: believe (<em>haʾămînû</em>) and you will be made firm (<em>tēʾāmēnû</em>), the same root. Faith has the same shape as its object — to trust the firm one is to become firm. This is the OT equivalent of &ldquo;he who believes in me will have everlasting life&rdquo; (John 6:47).</p>",
    "21": "<p>After consultation, Jehoshaphat appoints those who are to sing to YHWH and praise him in holy attire (<em>bᵉhaḏrat-qōḏeš</em>) as they go before the army: <em>hôḏû lYHWH kî lᵉʿôlām ḥasᵉḏô</em> — &ldquo;Give thanks to the LORD, for his steadfast love endures forever.&rdquo; The refrain that punctuates David&rsquo;s ark-procession (1 Chr 16:34, 41) and Solomon&rsquo;s temple dedication (2 Chr 7:3, 6) now precedes a military engagement — the same praise that accompanies worship in the temple leads the army into battle. The boundary between liturgy and combat dissolves: the praise is the weapon.</p>",
    "22": "<p><em>ûḇᵉʿēt hēḥēllû bᵉrinnāh ûtᵉhillāh nātan YHWH mᵉʾārᵉḇîm ʿal-bᵉnê ʿammôn... wayyinnāgᵉpû</em> — &ldquo;And when they began to sing and praise, the LORD set an ambush against the men of Ammon, Moab, and Mount Seir.&rdquo; <em>Bᵉʿēt hēḥēllû</em> — at the moment they began to sing. The timing is precise and theologically significant: divine action is triggered by the act of praise. The ambush that destroys the coalition begins not with Israel&rsquo;s swords but with Israel&rsquo;s song. YHWH fights for those who worship him.</p>",
    "23": "<p>The Ammonites and Moabites turn against the inhabitants of Mount Seir, destroying them utterly — then turn on each other. The coalition self-destructs: YHWH sets them fighting among themselves (a holy-war pattern seen also in Judg 7:22 at Gideon&rsquo;s battle: &ldquo;the LORD set every man&rsquo;s sword against his comrade&rdquo;). The enemies of God&rsquo;s people are not defeated by Israel&rsquo;s hand but by their own internal contradictions and divine confusion.</p>",
    "24": "<p>When Judah comes to the watchtower of the wilderness, they look toward the horde — only dead bodies (<em>pᵉgārîm nōpᵉlîm lāʾāreṣ wᵉʾên pālîṭ</em>), no one escaped. The totality of the divine victory — not one survivor — is the covenant language of complete judgment (ḥērem). Israel&rsquo;s role was to look and see the <em>yᵉšûʿāh</em> of YHWH (v17) — and now they literally look and see only corpses. The battle belonged to God; so did its outcome.</p>",
    "25": "<p>Three days to carry off the spoil — so much that they could not carry it all. <em>Wayyibzezû</em> (they plundered) — Israel comes to gather the spoil of a battle they did not fight. The reversal of military logic is complete: those who went out to fight found only praise-singers; those who went out to plunder found only corpses and wealth. The Chronicler presents this as the material consequence of divine-warrior theology: YHWH fights; Israel inherits.</p>",
    "26": "<p>On the fourth day they assemble in the Valley of Berachah (<em>ʿēmeq bᵉrāḵāh</em>) — the Valley of Blessing — for there they blessed YHWH. The naming of the valley after the corporate act of blessing (praise) is the Chronicler&rsquo;s benediction on the whole episode: geography is consecrated by the praise that happens in it. As Jacob named Peniel (&ldquo;Face of God&rdquo;) after his encounter with the divine (Gen 32:30), so the valley is named Berachah after Israel&rsquo;s corporate act of blessing the God who fought for them.</p>",
    "27": "<p>Every man of Judah and Jerusalem returns to Jerusalem with joy (<em>bᵉśimḥāh</em>), for YHWH had made them rejoice over their enemies. The joy of the return echoes the joy at the Passover celebrations, the ark procession, and the temple dedications — the Chronicler&rsquo;s consistent association of joy with YHWH&rsquo;s saving actions. The same joy that attends worship attends divine victory: they are theologically inseparable.</p>",
    "28": "<p>They come to Jerusalem with harps, lyres, and trumpets — entering the temple of the LORD. The victory procession enters the temple with instruments — the sacred music that began the campaign (v21) concludes it. The warriors become worshipers as they enter the temple; the procession of armed men becomes a liturgical procession. War ends in worship: this is the Chronicler&rsquo;s vision of the complete cycle of Israel&rsquo;s life before YHWH.</p>",
    "29": "<p>The fear of God (<em>paḥaḏ ʾĕlōhîm</em>) falls on all the kingdoms of the countries when they hear that YHWH has fought against the enemies of Israel. The universal report of divine intervention — the surrounding nations hearing of YHWH&rsquo;s battle — is the same missionary logic as Rahab at Jericho (Josh 2:9-11) and the Exodus report to Egypt&rsquo;s neighbors. YHWH&rsquo;s actions for Israel are simultaneously testimony to the nations about who YHWH is.</p>",
    "30": "<p>The kingdom of Jehoshaphat was at rest (<em>wayyišqōṭ mamlᵉḵet Yᵉhôšāpāṭ</em>), for his God gave him rest (<em>wayyānaḥ-lô ʾĕlōhāyw</em>) on every side. The <em>mᵉnûḥāh</em> (rest/quiet) given to the king who sought YHWH is the Davidic rest-promise enacted (2 Sam 7:1; 1 Chr 22:9) — and the temporal type of the eschatological rest that Hebrews promises to those who &ldquo;strive to enter&rdquo; by faith (Heb 4:11). The one who trusts YHWH in extremity receives <em>šālôm</em> and <em>mᵉnûḥāh</em> as consequence.</p>",
    "31": "<p>Jehoshaphat reigned over Judah; he was thirty-five years old when he began to reign, and he reigned twenty-five years in Jerusalem. The regnal formula frames the narrative unit: the extraordinary crisis of ch20 is embedded within an ordinary reign. The Chronicler&rsquo;s kings are evaluated not by the grandeur of their crises but by their relationship to YHWH throughout — <em>wayyᵃʿaś hayyāšār bᵉʿênê YHWH</em>: he did what was right in the eyes of YHWH.</p>",
    "32": "<p>He walked in the way of his father Asa and did not turn aside from it, doing what was right in the sight of the LORD. The Chronicler evaluates Jehoshaphat by the standard of his father rather than David — the narrower filial comparison allowing both positive and negative assessments. The high places were not removed (<em>habbāmôt lōʾ-sārû</em>) — the persistent fault of the otherwise faithful king. Even the good king leaves unfinished work; complete reform is a task that no single reign accomplishes.</p>",
    "33": "<p><em>wᵉhābāmôt lōʾ-sārû wᵉʿôḏ hāʿām lōʾ-hēḵînû libbābām lēʾlōhê ʾăḇōtêhem</em> — &ldquo;Nevertheless, the high places were not taken away, and the people had not yet set their hearts on the God of their fathers.&rdquo; The structural failure: despite Jehoshaphat&rsquo;s personal faithfulness and the extraordinary victory of ch20, the people&rsquo;s hearts have not been fundamentally redirected. The external reform does not produce the internal transformation — the problem that Jeremiah and Ezekiel name explicitly: only a new heart, inscribed by YHWH, will accomplish what no legal reform or military miracle can (Jer 31:33; Ezek 36:26).</p>",
    "34": "<p>The rest of the acts of Jehoshaphat are written in the chronicles of Jehu son of Hanani (who rebuked Jehoshaphat in 19:2 — the same prophet appears as a source author). The Chronicler&rsquo;s source-citation is also a theological statement: the prophet who rebuked the king is also the one who recorded him. Prophetic critique and prophetic record-keeping are the same office — the witness who confronts is the witness who preserves for posterity.</p>",
    "35": "<p>After this, Jehoshaphat allies with Ahaziah king of Israel — <em>wayiḥbᵉr</em> (he joined/allied) — another dangerous northern alliance, the mistake of ch18 repeated. <em>Hûʾ hêrᵉšîaʿ laʿăśôt</em> — Ahaziah &ldquo;acted wickedly.&rdquo; The characterization of the northern king as wicked frames the alliance as another covenantal misstep by Jehoshaphat: the reformed, praising king of ch20 is again drawn into the orbit of Israel&rsquo;s apostate north.</p>",
    "36": "<p>They made ships to go to Tarshish — a joint maritime venture. Tarshish ships are the prestige trading vessels of the ancient world (Isa 2:16; 23:1, 14; 60:9), associated with luxury commerce and far-off wealth. The commercial alliance with an apostate king for the sake of Tarshish-wealth is the economic version of the military alliance with Ahab: covenant faithfulness compromised for material gain.</p>",
    "37": "<p>Eliezer son of Dodavahu of Mareshah prophesies against Jehoshaphat: <em>bᵉhitḥabbᵉrᵉḵā ʿim-ʾAḥazyāhû pāraṣ YHWH ʾet-maʿăśêḵā</em> — &ldquo;Because you have joined with Ahaziah, the LORD will destroy what you have made.&rdquo; The ships are wrecked (<em>wayyiššāḇᵉrû hāʾăniyyôt</em>) and cannot go to Tarshish. The prophetic-consequence structure is precise: the alliance with the wicked one produces not wealth but wreckage. The Chronicler&rsquo;s bookend: ch20&rsquo;s triumphant king who trusted YHWH ends the chapter trusting Ahaziah, and loses the commercial enterprise accordingly.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '2chronicles')
    merge_comm(existing, CHRON2_ORIGINAL_18_20)
    save_comm('mkt-original', '2chronicles', existing)
    print('2 Chronicles 18-20 original layer written.')

if __name__ == '__main__':
    main()
